import { useState } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("clinical");

  const [patient, setPatient] = useState({
    name: "",
    age: "",
    gender: "",
    mrn: "",
    visitId: "",
    department: "",
    photo: "",
  });

  const [notes, setNotes] = useState({
    complaint: "",
    hpi: "",
    assessment: "",
    plan: "",
  });

  const [vitals, setVitals] = useState({
    hr: "",
    bpSys: "",
    bpDia: "",
    rr: "",
    spo2: "",
    temp: "",
    nurse: "",
    triage: "",
  });

  return (
    <div className="emr-container">

      {/* ================= PATIENT HEADER ================= */}
      <div className="emr-header">

        <div className="patient-left">
          <img
            src={
              patient.photo ||
              "https://cdn-icons-png.flaticon.com/512/847/847969.png"
            }
            alt="patient"
          />

          <div>
            <input
              placeholder="Patient Name"
              value={patient.name}
              onChange={(e) =>
                setPatient({ ...patient, name: e.target.value })
              }
            />

            <div className="sub">
              <input
                placeholder="Age"
                value={patient.age}
                onChange={(e) =>
                  setPatient({ ...patient, age: e.target.value })
                }
              />

              <input
                placeholder="Gender"
                value={patient.gender}
                onChange={(e) =>
                  setPatient({ ...patient, gender: e.target.value })
                }
              />
            </div>

            <div className="sub">
              <input
                placeholder="MRN"
                value={patient.mrn}
                onChange={(e) =>
                  setPatient({ ...patient, mrn: e.target.value })
                }
              />

              <input
                placeholder="Visit ID"
                value={patient.visitId}
                onChange={(e) =>
                  setPatient({ ...patient, visitId: e.target.value })
                }
              />

              <input
                placeholder="Department"
                value={patient.department}
                onChange={(e) =>
                  setPatient({ ...patient, department: e.target.value })
                }
              />
            </div>
          </div>
        </div>


      </div>

      {/* ================= TABS ================= */}
      <div className="tabs">
        <button
          className={tab === "clinical" ? "active" : ""}
          onClick={() => setTab("clinical")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "clinical" && (
        <div className="card">

          <label>Chief Complaint</label>
          <input
            value={notes.complaint}
            onChange={(e) =>
              setNotes({ ...notes, complaint: e.target.value })
            }
          />

          <label>History of Present Illness</label>
          <textarea
            value={notes.hpi}
            onChange={(e) =>
              setNotes({ ...notes, hpi: e.target.value })
            }
          />

          <label>Assessment</label>
          <textarea
            value={notes.assessment}
            onChange={(e) =>
              setNotes({ ...notes, assessment: e.target.value })
            }
          />

          <label>Plan</label>
          <textarea
            value={notes.plan}
            onChange={(e) =>
              setNotes({ ...notes, plan: e.target.value })
            }
          />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="card">

          <h3>Vital Signs</h3>

          <div className="vital-grid">
            <input placeholder="Heart Rate" onChange={(e)=>setVitals({...vitals,hr:e.target.value})}/>
            <input placeholder="BP Systolic" onChange={(e)=>setVitals({...vitals,bpSys:e.target.value})}/>
            <input placeholder="BP Diastolic" onChange={(e)=>setVitals({...vitals,bpDia:e.target.value})}/>
            <input placeholder="Respiratory Rate" onChange={(e)=>setVitals({...vitals,rr:e.target.value})}/>
            <input placeholder="SpO₂ %" onChange={(e)=>setVitals({...vitals,spo2:e.target.value})}/>
            <input placeholder="Temperature °C" onChange={(e)=>setVitals({...vitals,temp:e.target.value})}/>
          </div>

          {/* ===== TRIAGE ===== */}
          <div className="triage-box">
            <h4>AI Suggested Level</h4>
            <p className="ai">Auto calculated from vitals</p>

            <div className="triage-btns">
              <button className="l1">Level 1 Critical</button>
              <button className="l2">Level 2 Emergent</button>
              <button className="l3">Level 3 Urgent</button>
              <button className="l4">Level 4 Semi-Urgent</button>
              <button className="l5">Level 5 Non-Urgent</button>
            </div>
          </div>

          <label>Nurse Name</label>
          <input
            placeholder="Enter nurse name"
            onChange={(e) =>
              setVitals({ ...vitals, nurse: e.target.value })
            }
          />
        </div>
      )}

      {/* ================= ACTIONS ================= */}
      <div className="actions">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>
    </div>
  );
}
